using Microsoft.Extensions.Logging;

namespace MyMauiApp;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
            });

        // 1. Singleton — one HttpClient for the entire app lifetime.
        //    Avoids socket exhaustion from repeatedly creating/disposing HttpClients.
        builder.Services.AddSingleton(sp => new HttpClient
        {
            BaseAddress = new Uri("https://api.example.com/")
        });

        // 2. Singleton — one shared DataService instance.
        //    It wraps HttpClient and holds no per-user/per-page state,
        //    so every ViewModel can safely share the same instance.
        builder.Services.AddSingleton<IDataService, DataService>();

        // 3. Transient — a fresh ViewModel per navigation.
        //    ViewModels hold page-specific state (selected items, form fields).
        //    Transient ensures each page push gets a clean ViewModel,
        //    preventing stale data when navigating back and forth.
        builder.Services.AddTransient<MainViewModel>();
        builder.Services.AddTransient<DetailViewModel>();

        // 4. Transient — a fresh page per navigation.
        //    MAUI pages are lightweight; transient avoids retaining
        //    old UI state and pairs naturally with transient ViewModels.
        builder.Services.AddTransient<MainPage>();
        builder.Services.AddTransient<DetailPage>();

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

